using System.ComponentModel.DataAnnotations;

namespace sv_7bace2fbe257480f96af320f8d4e9e98.Models;

public class AppointmentFormModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone number is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string Reason { get; set; } = string.Empty;
}

public class PatientValidationResult
{
    public bool IsValid => Errors.Count == 0;
    public Dictionary<string, string> Errors { get; set; } = new();
}

using sv_7bace2fbe257480f96af320f8d4e9e98.Models;

namespace sv_7bace2fbe257480f96af320f8d4e9e98.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
        ["Dr. Smith", "Dr. Johnson", "Dr. Williams", "Dr. Brown"];

    private static readonly List<string> AllTimeSlots =
        ["9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM", "11:00 AM",
         "1:00 PM", "1:30 PM", "2:00 PM", "2:30 PM", "3:00 PM"];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return all slots for any doctor/date combination
        return Task.FromResult(new List<string>(AllTimeSlots));
    }

    public Task<PatientValidationResult> ValidatePatientAsync(AppointmentFormModel model)
    {
        var result = new PatientValidationResult();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(model.Email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors[nameof(model.Email)] = "Account has outstanding balance";
        }

        // Reject "None" insurance with Dr. Smith (doesn't accept self-pay)
        if (model.InsuranceProvider == "None"
            && string.Equals(model.Doctor, "Dr. Smith", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors[nameof(model.Doctor)] = "Selected doctor does not accept self-pay patients";
        }

        // Reject 10:00 AM slot as taken (simulates race condition)
        if (model.TimeSlot == "10:00 AM")
        {
            result.Errors[nameof(model.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_7bace2fbe257480f96af320f8d4e9e98.Models
@using sv_7bace2fbe257480f96af320f8d4e9e98.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="formModel" OnValidSubmit="HandleSubmitAsync">
    <DataAnnotationsValidator />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label class="form-label" for="patientName">Patient Name</label>
        <InputText id="patientName" class="form-control" @bind-Value="formModel.PatientName" />
        <ValidationMessage For="() => formModel.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="email">Email</label>
        <InputText id="email" class="form-control" @bind-Value="formModel.Email" />
        <ValidationMessage For="() => formModel.Email" />
        @if (serverErrors.ContainsKey(nameof(formModel.Email)))
        {
            <div class="validation-message">@serverErrors[nameof(formModel.Email)]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label" for="phone">Phone</label>
        <InputText id="phone" class="form-control" @bind-Value="formModel.Phone" />
        <ValidationMessage For="() => formModel.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="insurance">Insurance Provider</label>
        <InputSelect id="insurance" class="form-select" @bind-Value="formModel.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => formModel.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2Async">
            Next
        </button>
    }

    @if (showStep2)
    {
        <h3 class="mt-4">Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label class="form-label" for="doctor">Preferred Doctor</label>
            <InputSelect id="doctor" class="form-select" @bind-Value="formModel.Doctor"
                         @bind-Value:after="OnDoctorOrDateChangedAsync">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => formModel.Doctor" />
            @if (serverErrors.ContainsKey(nameof(formModel.Doctor)))
            {
                <div class="validation-message">@serverErrors[nameof(formModel.Doctor)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="date">Date</label>
            <InputDate id="date" class="form-control" @bind-Value="formModel.AppointmentDate"
                       @bind-Value:after="OnDoctorOrDateChangedAsync" />
            <ValidationMessage For="() => formModel.AppointmentDate" />
            @if (dateError is not null)
            {
                <div class="validation-message">@dateError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="timeSlot">Time Slot</label>
            <InputSelect id="timeSlot" class="form-select" @bind-Value="formModel.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => formModel.TimeSlot" />
            @if (serverErrors.ContainsKey(nameof(formModel.TimeSlot)))
            {
                <div class="validation-message">@serverErrors[nameof(formModel.TimeSlot)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="reason">Reason for Visit</label>
            <InputTextArea id="reason" class="form-control" @bind-Value="formModel.Reason" rows="3" />
            <ValidationMessage For="() => formModel.Reason" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailabilityAsync">
            Check Availability
        </button>
        <button type="submit" class="btn btn-primary" disabled="@(!availabilityChecked || serverErrors.Count > 0)">
            Book Appointment
        </button>

        @if (availabilityChecked && serverErrors.Count == 0)
        {
            <div class="alert alert-success mt-3">All checks passed. You may submit.</div>
        }
    }

    @if (submitted)
    {
        <div class="alert alert-success mt-3">
            <strong>Appointment booked successfully!</strong>
        </div>
    }
</EditForm>

@code {
    private AppointmentFormModel formModel = new();
    private List<string> doctors = new();
    private List<string> availableSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private string? dateError;
    private bool showStep2;
    private bool availabilityChecked;
    private bool submitted;

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task ProceedToStep2Async()
    {
        editContext = new EditContext(formModel);
        // Validate only step 1 fields
        var isValid = !string.IsNullOrWhiteSpace(formModel.PatientName)
                      && !string.IsNullOrWhiteSpace(formModel.Email)
                      && new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(formModel.Email)
                      && !string.IsNullOrWhiteSpace(formModel.Phone)
                      && !string.IsNullOrWhiteSpace(formModel.InsuranceProvider);

        if (isValid)
        {
            showStep2 = true;
            availabilityChecked = false;
            serverErrors.Clear();
        }
    }

    private async Task OnDoctorOrDateChangedAsync()
    {
        availableSlots.Clear();
        formModel.TimeSlot = string.Empty;
        availabilityChecked = false;
        serverErrors.Clear();

        if (!string.IsNullOrEmpty(formModel.Doctor) && formModel.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                formModel.Doctor, formModel.AppointmentDate.Value);
        }
    }

    private async Task CheckAvailabilityAsync()
    {
        serverErrors.Clear();
        dateError = null;
        availabilityChecked = false;

        // Client-side date validation
        if (!formModel.AppointmentDate.HasValue)
        {
            dateError = "Date is required.";
            return;
        }

        if (formModel.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            dateError = "Date must be in the future.";
            return;
        }

        // Validate step 2 fields locally before calling server
        if (string.IsNullOrWhiteSpace(formModel.Doctor)
            || string.IsNullOrWhiteSpace(formModel.TimeSlot)
            || string.IsNullOrWhiteSpace(formModel.Reason))
        {
            return;
        }

        if (formModel.Reason.Length > 500)
        {
            return;
        }

        var result = await AppointmentService.ValidatePatientAsync(formModel);

        if (!result.IsValid)
        {
            serverErrors = new Dictionary<string, string>(result.Errors);
        }

        availabilityChecked = true;
    }

    private async Task HandleSubmitAsync()
    {
        if (serverErrors.Count > 0 || !availabilityChecked)
            return;

        submitted = true;
    }
}

