@using sv_7bace2fbe257480f96af320f8d4e9e98.Models
@using sv_7bace2fbe257480f96af320f8d4e9e98.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="formModel" OnValidSubmit="HandleSubmitAsync">
    <DataAnnotationsValidator />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label class="form-label" for="patientName">Patient Name</label>
        <InputText id="patientName" class="form-control" @bind-Value="formModel.PatientName" />
        <ValidationMessage For="() => formModel.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="email">Email</label>
        <InputText id="email" class="form-control" @bind-Value="formModel.Email" />
        <ValidationMessage For="() => formModel.Email" />
        @if (serverErrors.ContainsKey(nameof(formModel.Email)))
        {
            <div class="validation-message">@serverErrors[nameof(formModel.Email)]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label" for="phone">Phone</label>
        <InputText id="phone" class="form-control" @bind-Value="formModel.Phone" />
        <ValidationMessage For="() => formModel.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="insurance">Insurance Provider</label>
        <InputSelect id="insurance" class="form-select" @bind-Value="formModel.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => formModel.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2Async">
            Next
        </button>
    }

    @if (showStep2)
    {
        <h3 class="mt-4">Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label class="form-label" for="doctor">Preferred Doctor</label>
            <InputSelect id="doctor" class="form-select" @bind-Value="formModel.Doctor"
                         @bind-Value:after="OnDoctorOrDateChangedAsync">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => formModel.Doctor" />
            @if (serverErrors.ContainsKey(nameof(formModel.Doctor)))
            {
                <div class="validation-message">@serverErrors[nameof(formModel.Doctor)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="date">Date</label>
            <InputDate id="date" class="form-control" @bind-Value="formModel.AppointmentDate"
                       @bind-Value:after="OnDoctorOrDateChangedAsync" />
            <ValidationMessage For="() => formModel.AppointmentDate" />
            @if (dateError is not null)
            {
                <div class="validation-message">@dateError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="timeSlot">Time Slot</label>
            <InputSelect id="timeSlot" class="form-select" @bind-Value="formModel.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => formModel.TimeSlot" />
            @if (serverErrors.ContainsKey(nameof(formModel.TimeSlot)))
            {
                <div class="validation-message">@serverErrors[nameof(formModel.TimeSlot)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="reason">Reason for Visit</label>
            <InputTextArea id="reason" class="form-control" @bind-Value="formModel.Reason" rows="3" />
            <ValidationMessage For="() => formModel.Reason" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailabilityAsync">
            Check Availability
        </button>
        <button type="submit" class="btn btn-primary" disabled="@(!availabilityChecked || serverErrors.Count > 0)">
            Book Appointment
        </button>

        @if (availabilityChecked && serverErrors.Count == 0)
        {
            <div class="alert alert-success mt-3">All checks passed. You may submit.</div>
        }
    }

    @if (submitted)
    {
        <div class="alert alert-success mt-3">
            <strong>Appointment booked successfully!</strong>
        </div>
    }
</EditForm>

@code {
