        }
    }

    private async Task CheckAvailabilityAsync()
    {
        serverErrors.Clear();
        dateError = null;
        availabilityChecked = false;

        // Client-side date validation
        if (!formModel.AppointmentDate.HasValue)
        {
            dateError = "Date is required.";
